 pub fn pyFloatMod(a: f64, b: f64) f64 {
     // Python's floored modulo: a - floor(a/b) * b
     // This ensures the result has the same sign as the divisor
-    return a - @floor(a / b) * b;
+    const result = a - @floor(a / b) * b;
